fn get_first(v: &[i32]) -> Option<i32> {
    let first = v.first()?;
    Some(*first * 2)
}

fn parse_header(data: &str) -> Result<u32, Box<dyn std::error::Error>> {
    let header = data.lines().next().ok_or("empty")?;
    let value = header.trim().parse::<u32>()?;
    Ok(value)
}

